record.field:
services:
  playwright-service:
    image: ghcr.io/firecrawl/playwright-service:latest
    shm_size: 1g
    restart: unless-stopped
    environment:
      PORT: 3000
      PROXY_SERVER: ${PROXY_SERVER:-}
      PROXY_USERNAME: ${PROXY_USERNAME:-}
      PROXY_PASSWORD: ${PROXY_PASSWORD:-}
      BLOCK_MEDIA: ${BLOCK_MEDIA:-}
      NO_PROXY: ${NO_PROXY:-localhost,127.0.0.1,redis,nuq-postgres,playwright-service,host.docker.internal}
    container_name: '{{ INSTANCE_CODE }}_playwright_service'
    networks:
    - internal
  api:
    image: ghcr.io/firecrawl/firecrawl:latest
    ulimits: &id001
      nofile:
        soft: 65535
        hard: 65535
    extra_hosts: &id002
    - host.docker.internal:host-gateway
    restart: unless-stopped
    ports:
    - '{{ PORT_HTTP }}:3002'
    environment:
      REDIS_URL: ${REDIS_URL:-redis://redis:6379}
      REDIS_RATE_LIMIT_URL: ${REDIS_RATE_LIMIT_URL:-redis://redis:6379}
      PLAYWRIGHT_MICROSERVICE_URL: ${PLAYWRIGHT_MICROSERVICE_URL:-http://playwright-service:3000/scrape}
      NUQ_DATABASE_URL: ${NUQ_DATABASE_URL:-postgres://postgres:postgres@nuq-postgres:5432/postgres}
      USE_DB_AUTHENTICATION: ${USE_DB_AUTHENTICATION:-}
      OPENAI_API_KEY: ${OPENAI_API_KEY:-}
      OPENAI_BASE_URL: ${OPENAI_BASE_URL:-}
      MODEL_NAME: ${MODEL_NAME:-}
      MODEL_EMBEDDING_NAME: ${MODEL_EMBEDDING_NAME:-}
      OLLAMA_BASE_URL: ${OLLAMA_BASE_URL:-}
      SLACK_WEBHOOK_URL: ${SLACK_WEBHOOK_URL:-}
      BULL_AUTH_KEY: ${BULL_AUTH_KEY:-}
      TEST_API_KEY: ${TEST_API_KEY:-}
      POSTHOG_API_KEY: ${POSTHOG_API_KEY:-}
      POSTHOG_HOST: ${POSTHOG_HOST:-}
      SUPABASE_ANON_TOKEN: ${SUPABASE_ANON_TOKEN:-}
      SUPABASE_URL: ${SUPABASE_URL:-}
      SUPABASE_SERVICE_TOKEN: ${SUPABASE_SERVICE_TOKEN:-}
      SELF_HOSTED_WEBHOOK_URL: ${SELF_HOSTED_WEBHOOK_URL:-}
      SERPER_API_KEY: ${SERPER_API_KEY:-}
      SEARCHAPI_API_KEY: ${SEARCHAPI_API_KEY:-}
      LOGGING_LEVEL: ${LOGGING_LEVEL:-INFO}
      PROXY_SERVER: ${PROXY_SERVER:-}
      PROXY_USERNAME: ${PROXY_USERNAME:-}
      PROXY_PASSWORD: ${PROXY_PASSWORD:-}
      NO_PROXY: ${NO_PROXY:-localhost,127.0.0.1,redis,nuq-postgres,playwright-service,host.docker.internal}
      SEARXNG_ENDPOINT: ${SEARXNG_ENDPOINT:-}
      SEARXNG_ENGINES: ${SEARXNG_ENGINES:-}
      SEARXNG_CATEGORIES: ${SEARXNG_CATEGORIES:-}
      HOST: 0.0.0.0
      PORT: 3002
      WORKER_PORT: 3005
      ENV: local
    depends_on:
      redis:
        condition: service_started
      playwright-service:
        condition: service_started
      nuq-postgres:
        condition: service_healthy
    command: node --import ./dist/src/otel.js dist/src/index.js
    container_name: '{{ INSTANCE_CODE }}'
    networks:
    - internal
    - agz-proxy-network
  worker:
    image: ghcr.io/firecrawl/firecrawl:latest
    ulimits: *id001
    extra_hosts: *id002
    restart: unless-stopped
    environment:
      REDIS_URL: ${REDIS_URL:-redis://redis:6379}
      REDIS_RATE_LIMIT_URL: ${REDIS_RATE_LIMIT_URL:-redis://redis:6379}
      PLAYWRIGHT_MICROSERVICE_URL: ${PLAYWRIGHT_MICROSERVICE_URL:-http://playwright-service:3000/scrape}
      NUQ_DATABASE_URL: ${NUQ_DATABASE_URL:-postgres://postgres:postgres@nuq-postgres:5432/postgres}
      USE_DB_AUTHENTICATION: ${USE_DB_AUTHENTICATION:-}
      OPENAI_API_KEY: ${OPENAI_API_KEY:-}
      OPENAI_BASE_URL: ${OPENAI_BASE_URL:-}
      MODEL_NAME: ${MODEL_NAME:-}
      MODEL_EMBEDDING_NAME: ${MODEL_EMBEDDING_NAME:-}
      OLLAMA_BASE_URL: ${OLLAMA_BASE_URL:-}
      SLACK_WEBHOOK_URL: ${SLACK_WEBHOOK_URL:-}
      BULL_AUTH_KEY: ${BULL_AUTH_KEY:-}
      TEST_API_KEY: ${TEST_API_KEY:-}
      POSTHOG_API_KEY: ${POSTHOG_API_KEY:-}
      POSTHOG_HOST: ${POSTHOG_HOST:-}
      SUPABASE_ANON_TOKEN: ${SUPABASE_ANON_TOKEN:-}
      SUPABASE_URL: ${SUPABASE_URL:-}
      SUPABASE_SERVICE_TOKEN: ${SUPABASE_SERVICE_TOKEN:-}
      SELF_HOSTED_WEBHOOK_URL: ${SELF_HOSTED_WEBHOOK_URL:-}
      SERPER_API_KEY: ${SERPER_API_KEY:-}
      SEARCHAPI_API_KEY: ${SEARCHAPI_API_KEY:-}
      LOGGING_LEVEL: ${LOGGING_LEVEL:-INFO}
      PROXY_SERVER: ${PROXY_SERVER:-}
      PROXY_USERNAME: ${PROXY_USERNAME:-}
      PROXY_PASSWORD: ${PROXY_PASSWORD:-}
      NO_PROXY: ${NO_PROXY:-localhost,127.0.0.1,redis,nuq-postgres,playwright-service,host.docker.internal}
      SEARXNG_ENDPOINT: ${SEARXNG_ENDPOINT:-}
      SEARXNG_ENGINES: ${SEARXNG_ENGINES:-}
      SEARXNG_CATEGORIES: ${SEARXNG_CATEGORIES:-}
      HOST: 0.0.0.0
      PORT: 3005
      ENV: local
    depends_on:
      redis:
        condition: service_started
      nuq-postgres:
        condition: service_healthy
    command: node --import ./dist/src/otel.js dist/src/services/queue-worker.js
    container_name: '{{ INSTANCE_CODE }}_worker'
    networks:
    - internal
  extract-worker:
    image: ghcr.io/firecrawl/firecrawl:latest
    ulimits: *id001
    extra_hosts: *id002
    restart: unless-stopped
    environment:
      REDIS_URL: ${REDIS_URL:-redis://redis:6379}
      REDIS_RATE_LIMIT_URL: ${REDIS_RATE_LIMIT_URL:-redis://redis:6379}
      PLAYWRIGHT_MICROSERVICE_URL: ${PLAYWRIGHT_MICROSERVICE_URL:-http://playwright-service:3000/scrape}
      NUQ_DATABASE_URL: ${NUQ_DATABASE_URL:-postgres://postgres:postgres@nuq-postgres:5432/postgres}
      USE_DB_AUTHENTICATION: ${USE_DB_AUTHENTICATION:-}
      OPENAI_API_KEY: ${OPENAI_API_KEY:-}
      OPENAI_BASE_URL: ${OPENAI_BASE_URL:-}
      MODEL_NAME: ${MODEL_NAME:-}
      MODEL_EMBEDDING_NAME: ${MODEL_EMBEDDING_NAME:-}
      OLLAMA_BASE_URL: ${OLLAMA_BASE_URL:-}
      SLACK_WEBHOOK_URL: ${SLACK_WEBHOOK_URL:-}
      BULL_AUTH_KEY: ${BULL_AUTH_KEY:-}
      TEST_API_KEY: ${TEST_API_KEY:-}
      POSTHOG_API_KEY: ${POSTHOG_API_KEY:-}
      POSTHOG_HOST: ${POSTHOG_HOST:-}
      SUPABASE_ANON_TOKEN: ${SUPABASE_ANON_TOKEN:-}
      SUPABASE_URL: ${SUPABASE_URL:-}
      SUPABASE_SERVICE_TOKEN: ${SUPABASE_SERVICE_TOKEN:-}
      SELF_HOSTED_WEBHOOK_URL: ${SELF_HOSTED_WEBHOOK_URL:-}
      SERPER_API_KEY: ${SERPER_API_KEY:-}
      SEARCHAPI_API_KEY: ${SEARCHAPI_API_KEY:-}
      LOGGING_LEVEL: ${LOGGING_LEVEL:-INFO}
      PROXY_SERVER: ${PROXY_SERVER:-}
      PROXY_USERNAME: ${PROXY_USERNAME:-}
      PROXY_PASSWORD: ${PROXY_PASSWORD:-}
      NO_PROXY: ${NO_PROXY:-localhost,127.0.0.1,redis,nuq-postgres,playwright-service,host.docker.internal}
      SEARXNG_ENDPOINT: ${SEARXNG_ENDPOINT:-}
      SEARXNG_ENGINES: ${SEARXNG_ENGINES:-}
      SEARXNG_CATEGORIES: ${SEARXNG_CATEGORIES:-}
      HOST: 0.0.0.0
      PORT: 3004
      ENV: local
    depends_on:
      redis:
        condition: service_started
      nuq-postgres:
        condition: service_healthy
    command: node --import ./dist/src/otel.js dist/src/services/extract-worker.js
    container_name: '{{ INSTANCE_CODE }}_extract_worker'
    networks:
    - internal
  redis:
    image: redis:alpine
    command: redis-server --bind 0.0.0.0
    container_name: '{{ INSTANCE_CODE }}_redis'
    restart: unless-stopped
    networks:
    - internal
  nuq-postgres:
    build:
      context: https://github.com/firecrawl/firecrawl.git#main:apps/nuq-postgres
      dockerfile: Dockerfile
    restart: unless-stopped
    environment:
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres
      POSTGRES_DB: postgres
    volumes:
    - ./nuq_pg_data:/var/lib/postgresql/data
    healthcheck:
      test:
      - CMD-SHELL
      - pg_isready -U $${POSTGRES_USER} -d $${POSTGRES_DB}
      start_period: 30s
      interval: 10s
      timeout: 5s
      retries: 10
    container_name: '{{ INSTANCE_CODE }}_nuq_postgres'
    networks:
    - internal
networks:
  internal:
    driver: bridge
  agz-proxy-network:
    external: true
